import React, { useState, useRef, useEffect } from 'react';
import { collegeData } from '../data/collegeData'; 
import { Bot, Send, X, Loader2 } from 'lucide-react';

// 🚨 KEY SPLIT (Safe for GitHub)
const part1 = "AIzaSyAzJtMQSarM6NT42";
const part2 = "Zz8dUK5VM3PqW7VoWM";
const API_KEY = part1 + part2; 

function ChatBot({ isOpen, onClose, onOpen }) {
  const [messages, setMessages] = useState([
    { text: "Hi! I'm CampusBot. I'm online. Ask me anything!", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    if (isOpen) messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isThinking, isOpen]);

  // --- 🧠 THE UNIVERSAL FETCHER ---
  // This function tries multiple models until one works.
  const fetchGeminiResponse = async (promptText) => {
    const modelsToTry = [
      "gemini-1.5-flash",       // Newest & Fastest
      "gemini-1.5-pro",         // Smarter
      "gemini-1.0-pro",         // Older/Stable
      "gemini-pro"              // Legacy
    ];

    for (const model of modelsToTry) {
      try {
        console.log(`Trying model: ${model}...`);
        const response = await fetch(
          `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${API_KEY}`,
          {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              contents: [{ parts: [{ text: promptText }] }]
            }),
          }
        );

        const data = await response.json();

        // If this model worked, return the answer!
        if (!data.error && data.candidates) {
          console.log(`✅ Success with ${model}`);
          return data.candidates[0].content.parts[0].text;
        }
        
        // If 404, we continue to the next model in the loop
        console.warn(`❌ ${model} failed:`, data.error?.message);

      } catch (e) {
        console.error(`Connection error on ${model}`);
      }
    }
    throw new Error("All models failed. Check API Key quota.");
  };

  const handleSend = async () => {
    if (!input.trim()) return;

    // 1. UI: Add User Message
    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);

    try {
      // 2. Prepare Context
      const systemContext = `
        You are "CampusBot" for ${collegeData?.collegeInfo?.name || "NIMIT"}.
        DATA:
        - Depts: ${collegeData?.collegeInfo?.departments?.join(", ")}
        - Events: ${collegeData?.collegeInfo?.campusLife?.majorEvents?.join(", ")}
        INSTRUCTIONS:
        1. Answer NIMIT questions using data.
        2. Answer General questions (Math/Code) using your own knowledge.
        3. Be short and helpful.
      `;

      // 3. 🚨 CALL THE UNIVERSAL FETCHER
      const aiResponse = await fetchGeminiResponse(systemContext + "\n\nUser Question: " + userMsg.text);

      // 4. UI: Add AI Message
      setIsThinking(false);
      setMessages((prev) => [...prev, { text: aiResponse, isBot: true }]);

    } catch (error) {
      console.error("Final Error:", error);
      setIsThinking(false);
      setMessages((prev) => [...prev, { text: "⚠️ System busy. Please try again.", isBot: true }]);
    }
  };

  // --- UI RENDER ---
  return (
    <div className="fixed bottom-6 right-6 z-50 font-sans">
      {!isOpen && (
        <button onClick={onOpen} className="w-14 h-14 bg-indigo-600 rounded-full shadow-lg flex items-center justify-center border border-white/20 animate-bounce text-white">
          <Bot size={24} />
        </button>
      )}

      {isOpen && (
        <div className="w-[350px] md:w-[380px] h-[500px] bg-[#0a0a0a] border border-white/20 rounded-2xl shadow-2xl flex flex-col overflow-hidden">
          <div className="bg-indigo-900/50 border-b border-white/10 p-4 flex items-center justify-between">
            <span className="text-white font-bold flex gap-2"><Bot size={20}/> CampusBot</span>
            <button onClick={onClose} className="text-gray-400 hover:text-white"><X size={20} /></button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[85%] p-3 text-sm rounded-xl ${!msg.isBot ? 'bg-indigo-600 text-white' : 'bg-[#1a1a1a] text-gray-200 border border-white/10'}`}>
                  {msg.text.split('```').map((part, i) => i % 2 === 1 ? <code key={i} className="block bg-black/50 p-2 text-xs my-1">{part}</code> : <span key={i}>{part}</span>)}
                </div>
              </div>
            ))}
            {isThinking && <div className="text-indigo-400 text-xs p-2 animate-pulse">Trying to connect...</div>}
            <div ref={messagesEndRef} />
          </div>

          <div className="p-3 bg-black border-t border-white/10 flex gap-2">
            <input 
              type="text" 
              value={input} 
              onChange={(e) => setInput(e.target.value)} 
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask anything..." 
              className="flex-1 bg-[#1a1a1a] border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500"
            />
            <button onClick={handleSend} disabled={isThinking} className="bg-indigo-600 p-2 rounded-lg text-white disabled:opacity-50"><Send size={18} /></button>
          </div>
        </div>
      )}
    </div>
  );
}

export default ChatBot;
